1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	const BASE_PREMIUM: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
16	
17	type Item = { type: string; cursed?: boolean };
18	const CURSE_RATE = 0.5;
19	type QuoteStep = { op: "quote"; items: Item[] };
20	type Input = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
21	type QuoteResult = { premium: number };
22	
23	const countByType = (items: Item[]): Map<string, number> => {
24	  const counts = new Map<string, number>();
25	  for (const item of items) {
26	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
27	  }
28	  return counts;
29	};
30	
31	const basePremiumForType = (type: string, count: number): number => {
32	  const unit = BASE_PREMIUM[type];
33	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
34	    return BLOCK_BASE_PREMIUM;
35	  }
36	  return unit * count;
37	};
38	
39	const basePremium = (items: Item[]): number =>
40	  Array.from(countByType(items)).reduce(
41	    (total, [type, count]) => total + basePremiumForType(type, count),
42	    0,
43	  );
44	
45	// MHPCO always rounds premiums in its own favor (up).
46	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
47	
48	const itemSurcharges = (item: Item): number => {
49	  const unit = BASE_PREMIUM[item.type];
50	  return item.cursed ? unit * CURSE_RATE : 0;
51	};
52	
53	const sumItemSurcharges = (items: Item[]): number =>
54	  items.reduce((total, item) => total + itemSurcharges(item), 0);
55	
56	const quotePremium = (step: QuoteStep): QuoteResult => {
57	  const base = basePremium(step.items);
58	  const surcharges = sumItemSurcharges(step.items);
59	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
60	  return {
61	    premium: roundUpInMHPCOFavor(
62	      base + surcharges + firstInsuranceSurcharge + PROCESSING_FEE,
63	    ),
64	  };
65	};
66	
67	export const run = (input: Input): { results: QuoteResult[] } => ({
68	  results: input.steps.map(quotePremium),
69	});
